ight_lb`, _Product_List_DataSet.`sku_reorder_status`, _Product_List_DataSet.`upc_reorder_status`, _Product_List_DataSet.`is_discontinued_status`, _Product_List_DataSet.`upc_components`, _Product_List_DataSet.`catalog_last_appearance`, _Product_List_DataSet.`parent_category`, _Product_List_DataSet.`child_category`, _Product_List_DataSet.`child_category_3`, _Product_List_DataSet.`child_category_2`, _Product_List_DataSet.`sku_reorder_comments`, _Product_List_DataSet.`upc_reorder_comments`, _Product_List_DataSet.`is_preferred_sku_by_asin`, _Product_List_DataSet.`seller_name`, _Product_List_DataSet.`countries.name`, _Product_List_DataSet.`sku created date`, _Product_List_DataSet.`upc created date`, _Product_List_DataSet.`sku_cost`, _Product_List_DataSet.`is_current`, _Product_List_DataSet.`fulfillment_channel`, _Product_List_DataSet.`last_seen_price`, _Product_List_DataSet.`last_known_price`, _Product_List_DataSet.`estimated_units_sold_last_month`, _Product_List_DataSet.`hero`, _Product_List_DataSet.`upc_count_total_components`, _Product_List_DataSet.`brand_created_at`, _Product_List_DataSet.`seller_start_date`, _Product_List_DataSet.`brand_start_date`, _Product_List_DataSet.`amazon_seller_central_accounts_created_at`, _Product_List_DataSet.`BP Partner Name`, _Product_List_DataSet.`BP Brand Name`, _Product_List_DataSet.`Partner - Brand`, _Product_List_DataSet.`seller_created_at`, _Product_List_DataSet.`Preferred_SKU(s) on ASIN`, _Product_List_DataSet.`QA - Count FBM Offers (Current)`, _Product_List_DataSet.`QA - Count FBA Offers (Current)`, _Product_List_DataSet.`QA -Count reorder Status Yes`, _Product_List_DataSet.`QA -Count Preferred_SKU(s)`, _Product_List_DataSet.`QA -Current_Preferred_SKU(s)`, _Product_List_DataSet.`is_current_ASIN`, _Product_List_DataSet.`name`, _Product_List_DataSet.`upc_name` FROM _Alter_Columns LEFT JOIN _Product_List_DataSet ON _Alter_Columns.`msku` = _Product_List_DataSet.`sku`
),

_Group_By_PO_and_partner AS (
  SELECT `number`, `invoiced`, `current_status`, `created`, `processed`, `shipped`, `approved`, `po_cancelled`, `vendor_invoice_date`, `vendor_invoice_number`, `partner name`, `vendor_name`, `received`, `Brand`, SUM(`extended_cost_invoiced`) AS `extended_cost_invoiced`, SUM(`created_qty`) AS `created_qty`, SUM(`approved_qty`) AS `approved_qty`, SUM(`invoiced_qty`) AS `invoiced_qty`, SUM(`received_qty`) AS `received_qty`, SUM(`extended_cost_approved`) AS `extended_cost_approved`, MAX(`type`) AS `type`, MAX(`priority`) AS `priority`, MAX(`shipping_method`) AS `shipping_method`, MAX(`memo`) AS `memo`, AVG(`lead_time`) AS `lead_time`, AVG(`Invoiced_invoice_total`) AS `Invoiced_invoice_total` FROM _Extended_Cost GROUP BY `number`, `invoiced`, `current_status`, `created`, `processed`, `shipped`, `approved`, `po_cancelled`, `vendor_invoice_date`, `vendor_invoice_number`, `partner name`, `vendor_name`, `received`, `Brand`
),

_Add_Formula_5 AS (
  SELECT `number`, `amazon_seller_id`, `upc`, `approved`, `invoiced`, `received`, `processed`, `shipped`, `current_status`, `Invoiced_invoice_total`, `po_cancelled`, `vendor_invoice_date`, `vendor_invoice_number`, `vendor_name`, `created_qty`, `approved_qty`, `invoiced_qty`, `received_qty`, `processed_qty`, `shipped_qty`, `type`, `priority`, `shipping_method`, `memo`, `partner name`, `Brand`, `upc_name`, `cost`, `wholesale_price`, `map`, `srp`, `extended_cost_invoiced`, `extended_cost_approved`, `lead_time`, (DATE_FORMAT(`invoiced`, '%M-%Y')) AS `month-year` FROM _Extended_Cost
),

_select_by_upc AS (
  SELECT `amazon_seller_id`, `number` AS `po_number`, `po_cancelled`, `current_status`, `created`, `approved`, `invoiced`, `received`, `processed`, `shipped`, `upc`, `created_qty`, `approved_qty`, `invoiced_qty`, `received_qty`, `processed_qty`, `shipped_qty`, `Brand`, `partner name`, `cost`, `wholesale_price`, `map`, `upc_name`, `Extended Cost`, `Invoiced_invoice_total`, `vendor_invoice_date`, `vendor_invoice_number`, `srp` AS `msrp`, `vendor_name`, `priority`, `type`, `shipping_method`, `memo` FROM _Extended_Cost_1
),

_Select_Columns_1 AS (
  SELECT `msku`, `asin`, `last_invoice_date`, `upc`, `upc_name`, `most_recent_memo`, `most_recent_po_number` FROM _Join_Data_1
),

_Select_Columns AS (
  SELECT `number` AS `po_number`, `invoiced`, `current_status`, `created`, `processed`, `shipped`, `Invoiced_invoice_total`, `approved`, `po_cancelled`, `vendor_invoice_date`, `vendor_invoice_number`, `partner name`, `vendor_name`, `extended_cost_invoiced`, `created_qty`, `approved_qty`, `invoiced_qty`, `received_qty`, `extended_cost_approved`, `type`, `priority`, `shipping_method`, `memo`, `received`, `lead_time`, `Brand` FROM _Group_By_PO_and_partner
),

_Group_By_4 AS (
  SELECT `Brand`, `month-year`, SUM(`approved_qty`) AS `approved_qty`, SUM(`invoiced_qty`) AS `invoiced_qty`, SUM(`received_qty`) AS `received_qty`, AVG(`Invoiced_invoice_total`) AS `Invoiced_invoice_total` FROM _Add_Formula_5 GROUP BY `Brand`, `month-year`
),

_Filter_Rows_1 AS (
  SELECT * FROM _select_by_upc WHERE (`current_status` NOT LIKE '%approved%') OR (`current_status` NOT LIKE '%created%') OR (`vendor_invoice_date` IS NOT NULL)
),

_MSKU_w_ASIN_Last_Order_Date AS (
  SELECT * FROM _Select_Columns_1
),

_Alter_Columns_1 AS (
  SELECT CAST(`invoiced` AS DATE), CAST(`created` AS DATE), CAST(`processed` AS DATE), CAST(`shipped` AS DATE), CAST(`approved` AS DATE), CAST(`vendor_invoice_date` AS DATE), CAST(`received` AS DATE), `po_number`, `current_status`, `Invoiced_invoice_total`, `po_cancelled`, `vendor_invoice_number`, `partner name`, `vendor_name`, `extended_cost_invoiced`, `created_qty`, `approved_qty`, `invoiced_qty`, `received_qty`, `extended_cost_approved`, `type`, `priority`, `shipping_method`, `memo`, `lead_time`, `Brand` FROM _Select_Columns
),

_Join_Data_3 AS (
  SELECT _Group_By_5.`Brand`, _Group_By_5.`month-year`, _Group_By_5.`item_price`, _Group_By_4.`approved_qty`, _Group_By_4.`invoiced_qty`, _Group_By_4.`received_qty`, _Group_By_4.`Invoiced_invoice_total` FROM _Group_By_5 INNER JOIN _Group_By_4 ON _Group_By_5.`month-year` = _Group_By_4.`month-year` AND _Group_By_5.`Brand` = _Group_By_4.`Brand`
),

_step_180_Days AS (
  SELECT * FROM _Filter_Rows_1 WHERE `invoiced`> CURDATE()-180
),

_step_60_Day AS (
  SELECT * FROM _Filter_Rows_1 WHERE `invoiced`> CURDATE()-60
),

_Jan_Feb_22_Fill_Rate_by_UPC_1 AS (
  SELECT * FROM _Filter_Rows_1 WHERE (`invoiced` >= '2022-01-01' AND `invoiced` <= '2022-02-25')
),

_Group_By AS (
  SELECT `partner name`, `Brand`, AVG(`lead_time`) AS `lead_time_avg`, STDDEV(`lead_time`) AS `lead_time_std` FROM _Alter_Columns_1 GROUP BY `partner name`, `Brand`
),

_Remove_Duplicates AS (
  SELECT DISTINCT * FROM _Alter_Columns_1
),

_Sales_Purchases_draft AS (
  SELECT * FROM _Join_Data_3
),

_Add_Formula AS (
  SELECT `amazon_seller_id`, `po_number`, `po_cancelled`, `current_status`, `approved`, `invoiced`, `received`, `processed`, `shipped`, `upc`, `created_qty`, `approved_qty`, `invoiced_qty`, `received_qty`, `processed_qty`, `shipped_qty`, `Brand`, `partner name`, `cost`, `wholesale_price`, `map`, `upc_name`, `Extended Cost`, `Invoiced_invoice_total`, `vendor_invoice_date`, `vendor_invoice_number`, `msrp`, `vendor_name`, `priority`, `type`, `shipping_method`, `memo`, (MONTH(`approved`)) AS `Month`, (YEAR(`approved`)) AS `Year` FROM _step_180_Days
),

_Add_Formula_2 AS (
  SELECT `amazon_seller_id`, `po_number`, `po_cancelled`, `current_status`, `approved`, `invoiced`, `received`, `processed`, `shipped`, `upc`, `created_qty`, `approved_qty`, `invoiced_qty`, `received_qty`, `processed_qty`, `shipped_qty`, `Brand`, `partner name`, `cost`, `wholesale_price`, `map`, `upc_name`, `Extended Cost`, `Invoiced_invoice_total`, `vendor_invoice_date`, `vendor_invoice_number`, `msrp`, `vendor_name`, `priority`, `type`, `shipping_method`, `memo`, (MONTH(`approved`)) AS `Month`, (YEAR(`approved`)) AS `Year` FROM _step_60_Day
),

_Add_Formula_6 AS (
  SELECT `amazon_seller_id`, `po_number`, `po_cancelled`, `current_status`, `approved`, `invoiced`, `received`, `processed`, `shipped`, `upc`, `created_qty`, `approved_qty`, `invoiced_qty`, `received_qty`, `processed_qty`, `shipped_qty`, `Brand`, `partner name`, `cost`, `wholesale_price`, `map`, `upc_name`, `Extended Cost`, `Invoiced_invoice_total`, `vendor_invoice_date`, `vendor_invoice_number`, `msrp`, `vendor_name`, `priority`, `type`, `shipping_method`, `memo`, (MONTH(`approved`)) AS `Month`, (YEAR(`approved`)) AS `Year` FROM _Jan_Feb_22_Fill_Rate_by_UPC_1
),

_Join_Data_2 AS (
  SELECT _Group_By_3.`partner name`, _Group_By_3.`Brand`, _Group_By_3.`sales`, _Group_By_3.`sales_std`, _Group_By.`lead_time_avg`, _Group_By.`lead_time_std` FROM _Group_By_3 RIGHT JOIN _Group_By ON _Group_By_3.`partner name` = _Group_By.`partner name` AND _Group_By_3.`Brand` = _Group_By.`Brand`
),

_PO_Invoices_by_Partner AS (
  SELECT * FROM _Remove_Duplicates
),

_Group_By_1 AS (
  SELECT `upc`, `Brand`, `upc_name`, `partner name`, `amazon_seller_id`, SUM(`approved_qty`) AS `approved_qty`, SUM(`received_qty`) AS `received_qty`, SUM(`invoiced_qty`) AS `invoiced_qty`, SUM(`created_qty`) AS `created_qty` FROM _Add_Formula GROUP BY `upc`, `Brand`, `upc_name`, `partner name`, `amazon_seller_id`
),

_Group_By_2 AS (
  SELECT `upc`, `Brand`, `partner name`, `upc_name`, `amazon_seller_id`, SUM(`created_qty`) AS `created_qty`, SUM(`approved_qty`) AS `approved_qty`, SUM(`invoiced_qty`) AS `invoiced_qty`, SUM(`received_qty`) AS `received_qty` FROM _Add_Formula_2 GROUP BY `upc`, `Brand`, `partner name`, `upc_name`, `amazon_seller_id`
),

_Group_By_6 AS (
  SELECT `upc`, `Brand`, `partner name`, `upc_name`, `amazon_seller_id`, SUM(`created_qty`) AS `created_qty`, SUM(`approved_qty`) AS `approved_qty`, SUM(`invoiced_qty`) AS `invoiced_qty`, SUM(`received_qty`) AS `received_qty` FROM _Add_Formula_6 GROUP BY `upc`, `Brand`, `partner name`, `upc_name`, `amazon_seller_id`
),

_Join_vendor_lead_times AS (
  SELECT _select_by_upc.`amazon_seller_id`, _select_by_upc.`po_number`, _select_by_upc.`po_cancelled`, _select_by_upc.`current_status`, _select_by_upc.`approved`, _select_by_upc.`invoiced`, _select_by_upc.`received`, _select_by_upc.`processed`, _select_by_upc.`shipped`, _select_by_upc.`upc`, _select_by_upc.`created_qty`, _select_by_upc.`approved_qty`, _select_by_upc.`invoiced_qty`, _select_by_upc.`received_qty`, _select_by_upc.`processed_qty`, _select_by_upc.`shipped_qty`, _select_by_upc.`Brand`, _select_by_upc.`partner name`, _select_by_upc.`cost`, _select_by_upc.`wholesale_price`, _select_by_upc.`map`, _select_by_upc.`upc_name`, _select_by_upc.`Extended Cost`, _select_by_upc.`Invoiced_invoice_total`, _select_by_upc.`vendor_invoice_date`, _select_by_upc.`vendor_invoice_number`, _select_by_upc.`msrp`, _select_by_upc.`vendor_name`, _select_by_upc.`priority`, _select_by_upc.`type`, _select_by_upc.`shipping_method`, _select_by_upc.`memo`, _Join_Data_2.`sales`, _Join_Data_2.`sales_std`, _Join_Data_2.`lead_time_avg`, _Join_Data_2.`lead_time_std` FROM _select_by_upc LEFT JOIN _Join_Data_2 ON _select_by_upc.`partner name` = _Join_Data_2.`partner name` AND _select_by_upc.`Brand` = _Join_Data_2.`Brand`
),

_Partner_Lead_Times AS (
  SELECT * FROM _Join_Data_2
),

_Add_Formula_1 AS (
  SELECT `upc`, `Brand`, `upc_name`, `partner name`, `amazon_seller_id`, `approved_qty`, `received_qty`, `invoiced_qty`, `created_qty`, (`invoiced_qty`/ `created_qty`) AS `180 Day Fill Rate`, (`created_qty` / `approved_qty`) AS `180 Day Cut Rate` FROM _Group_By_1
),

_Add_Formula_3 AS (
  SELECT `upc`, `Brand`, `partner name`, `upc_name`, `amazon_seller_id`, `created_qty`, `approved_qty`, `invoiced_qty`, `received_qty`, (`invoiced_qty`/ `created_qty`) AS `60 Day Fill Rate`, (`created_qty`/ `approved_qty`	) AS `60 Day Cut Rate` FROM _Group_By_2
),

_Add_Formula_7 AS (
  SELECT `upc`, `Brand`, `partner name`, `upc_name`, `amazon_seller_id`, `created_qty`, `approved_qty`, `invoiced_qty`, `received_qty`, (`invoiced_qty`/ `created_qty`) AS `Fill Rate` FROM _Group_By_6
),

_Purchase_Orders_Details_by_UPC_DS AS (
  SELECT * FROM _Join_vendor_lead_times
),

_step_180_Day_Fill_Rate_by_UPC AS (
  SELECT * FROM _Add_Formula_1
),

_step_60_Day_Fill_Rate_by_UPC AS (
  SELECT * FROM _Add_Formula_3
),

_Jan_Feb_22_Fill_Rate_by_UPC AS (
  SELECT * FROM _Add_Formula_7
)

